var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……열차를 멈출 방법이 없다고?","JPN":"……列車を止める方法が、ない？","ENG":"...There's no way to stop the train?","TWN":"……沒有能讓列車停下的方法？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"객차를 넘어 오면서 알아채지 않았나요?","JPN":"客車を通りながら、気付きませんでしたか？","ENG":"Did you not notice as you moved through the passenger cars?","TWN":"你一路這樣越過車廂都沒發現嗎？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"이 열차는 <color=#ffd34c>제</color>가 원하는 한 끝없이 달리게 정해져 있답니다.","JPN":"この列車は<color=#ffd34c>私</color>が望む限り、限りなく走るようになっているのです。","ENG":"This train will run endlessly as long as <color=#ffd34c>I</color> want it to.","TWN":"只要<color=#ffd34c>我</color>想要，就可以讓這台列車一直奔馳下去。"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"완벽한 합주를 추구하는 그녀에게 돌이킬 수 없는 실패는 참으로 흉측한 것일 뿐.","JPN":"完璧な合奏を追求する彼女にとって、取り返しのつかない失敗は耳障りな音そのものです。","ENG":"An irreversible failure is truly hideous for someone like her who only seeks perfect harmony.","TWN":"對於追求完美合奏的她而言，無法挽回的失敗是如此醜陋。"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"열차의 운행에 간섭할 여지를 남겨 둘 리 없지요.","JPN":"列車の運行に干渉する余地を残しておくわけがありません。","ENG":"She will never allow interference of any kind.","TWN":"所以她不會留下任何會影響到列車行進的餘地。"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"당신이 여기 있다는 말은……. 이 열차를 움직이는 원동력이 당신이란 뜻이지?","JPN":"君がここにいるってことは……この列車を動かす原動力が君だってことよね。","ENG":"And seeing how you are here... The driving force of this train is you, I presume?","TWN":"你之所以在這裡……是因為你就是這台列車的驅動力？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"네. 인간으로서의 마지막 경험이기 때문이지요.","JPN":"はい。人間としての最後の経験ですから。","ENG":"Correct. For I am my last experience as a human.","TWN":"沒錯，這裡是我身為人類時最後的經歷。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그게 뭔지 말해 줘. 열차를 멈출 실마리가 될지도 모르니까.","JPN":"それが何なのか話して。列車を止める手がかりになるかもしれないから。","ENG":"Tell me what that is. It might be a clue to stopping this train.","TWN":"告訴我那段經歷，那可能是能夠讓列車停下的線索。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"흥미롭군요. 그렇게나 열차에서 내리고 싶으신가요?","JPN":"興味深いですね。そんなに列車から降りたいのですか？","ENG":"Interesting. Are you that eager to get off this train?","TWN":"真有趣，你就那麼想離開這台列車嗎？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"이미 벌어졌던 참상을 엿보기나 하는 악취미는 없어서.","JPN":"すでに起きた惨状を盗み見る悪趣味は持ってないの。","ENG":"Well, I have no interest in revisiting tragedies that have already happened.","TWN":"我對窺視早已發生的慘況沒有興趣。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그렇군요.","JPN":"なるほど。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"새로운 타기리온이 강림한 그 날, 저는 인정했습니다.","JPN":"新しいタギリオンが降臨したあの日、私は認めました。","ENG":"On the day the new Thagirion descended, I admitted my defeat.","TWN":"新的塔基里翁降臨的那一天，我便清楚，"},"stage":{"bg":"HARMONY2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"아니. 처음부터 알고 있었지요.","JPN":"いいえ。最初からわかっていたのです。","ENG":"No, I always knew from the beginning.","TWN":"不，其實我早就知道。"},"stage":{"bg":"HARMONY2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"우리 세계의 문명 수준으로는 멘탈 프린팅은 실현 불가능한 기술이란 것을.","JPN":"私たちの世界の文明レベルでは、メンタル・プリンティングなど実用不可能な技術であるということは。","ENG":"That Mental Printing technology would be impossible to accomplish in our world's current state of civilization.","TWN":"以我們的文明水準，是不可能實現智力複印的。"},"stage":{"bg":"HARMONY2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"혹은, 애초에 구현할 수 없는 기술이란 것을.","JPN":"いいえ、具現化すらできない技術であるということは。","ENG":"That, or this technology could not be implemented in the first place.","TWN":"或者說，那項技術根本就無法實現。"},"stage":{"bg":"HARMONY2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……뭐?","JPN":"……は？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};